import{_ as a,o as e,c as i,ag as n}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Building ArduPilot","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/ardusub/compiling/building-ardupilot.md","filePath":"robotics/ardusub/compiling/building-ardupilot.md"}'),t={name:"robotics/ardusub/compiling/building-ardupilot.md"};function p(l,s,o,r,d,h){return e(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="building-ardupilot" tabindex="-1">Building ArduPilot <a class="header-anchor" href="#building-ardupilot" aria-label="Permalink to &quot;Building ArduPilot&quot;">​</a></h1><h2 id="get-the-source" tabindex="-1">Get the Source <a class="header-anchor" href="#get-the-source" aria-label="Permalink to &quot;Get the Source&quot;">​</a></h2><p>Clone the project from GitHub:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git clone </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">recursive https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">github.com</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ArduPilot</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ardupilot.git</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cd ardupilot</span></span></code></pre></div><p>ArduPilot is gradually moving from the make-based build system to <a href="https://waf.io/" target="_blank" rel="noreferrer">Waf</a>. The instructions below should be enough for you to build ArduPilot, but you can also read more about the build system in the <a href="https://waf.io/book/" target="_blank" rel="noreferrer">Waf Book</a>.</p><p>Waf should always be called from the ardupilot&#39;s root directory. Differently from the make-based build, with Waf there&#39;s a configure step to choose the board to be used (default is <code>sitl</code>).</p><h3 id="basic-usage" tabindex="-1">Basic usage <a class="header-anchor" href="#basic-usage" aria-label="Permalink to &quot;Basic usage&quot;">​</a></h3><p>There are several commands in the build system for advanced usages, but here we list some basic and more used commands as example.</p><ul><li><p><strong>Build ArduCopter</strong></p><p>Below shows how to build ArduCopter for the Pixhawk2/Cube. Many other boards are supported and the next section shows how to get a full list of them.</p></li></ul><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">waf configure </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">board CubeBlack</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">waf copter</span></span></code></pre></div><pre><code>The first command should be called only once or when you want to change a configuration option. One configuration often used is the \`--board\` option to switch from one board to another one. For example we could switch to SkyViper GPS drone and build again:

\`\`\`
./waf configure --board skyviper-v2450
./waf copter
\`\`\`

If building for the Bebop 2, the binary must be built statically:

\`\`\`
./waf configure --board bebop --static
./waf copter
\`\`\`

The &quot;arducopter&quot; binary should appear in the \`build/&lt;board-name&gt;/bin\` directory.
</code></pre><ul><li><p><strong>List available boards</strong></p><p>It&#39;s possible to get a list of supported boards on ArduPilot with the command below</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>./waf list_boards</span></span></code></pre></div><p>Here are some commands to configure waf for commonly used boards:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>./waf configure --board bebop --static # Bebop or Bebop2</span></span>
<span class="line"><span>./waf configure --board edge           # emlid edge</span></span>
<span class="line"><span>./waf configure --board fmuv3          # 3DR Pixhawk 2 boards</span></span>
<span class="line"><span>./waf configure --board navio2         # emlid navio2</span></span>
<span class="line"><span>./waf configure --board Pixhawk1       # Pixhawk1</span></span>
<span class="line"><span>./waf configure --board CubeBlack      # Hex/ProfiCNC Cube Black (formerly known as Pixhawk 2.1)</span></span>
<span class="line"><span>./waf configure --board Pixracer       # Pixracer</span></span>
<span class="line"><span>./waf configure --board skyviper-v2450 # SkyRocket&#39;s SkyViper GPS drone using ChibiOS</span></span>
<span class="line"><span>./waf configure --board sitl           # software-in-the-loop simulator</span></span>
<span class="line"><span>./waf configure --board sitl --debug   # software-in-the-loop simulator with debug symbols</span></span></code></pre></div></li><li><p><strong>List of available vehicle types</strong></p><p>Here is a list of the most common vehicle build targets:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>./waf copter                            # All multirotor types</span></span>
<span class="line"><span>./waf heli                              # Helicopter types</span></span>
<span class="line"><span>./waf plane                             # Fixed wing airplanes including VTOL</span></span>
<span class="line"><span>./waf rover                             # Ground-based rovers and surface boats</span></span>
<span class="line"><span>./waf sub                               # ROV and other submarines</span></span>
<span class="line"><span>./waf antennatracker                    # Antenna trackers</span></span></code></pre></div></li><li><p><strong>Clean the build</strong></p><p>Commands <code>clean</code> and <code>distclean</code> can be used to clean the objects produced by the build. The first keeps the <code>configure</code> information, cleaning only the objects for the current board. The second cleans everything for every board, including the saved <code>configure</code> information.</p><p>Cleaning the build is very often not necessary and discouraged. We do incremental builds reducing the build time by orders of magnitude.</p></li><li><p><strong>Upload or install</strong></p><p>Build commands have a <code>--upload</code> option in order to upload the binary built to a connected board. This option is supported by Pixhawk and Linux-based boards. The command below uses the <code>--targets</code> option that is explained in the next item.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>./waf --targets bin/arducopter --upload</span></span></code></pre></div><p>For Linux boards you need first to configure the IP of the board you are going to upload to. This is done on configure phase with:</p></li></ul><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">waf configure </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">board </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">board</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rsync</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dest </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">destination</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><pre><code>The commands below give a concrete example (board and destination IP will change according to the board used):
</code></pre><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">waf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> configure</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">board</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> navio2</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsync</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">dest</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> root</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">192.168.1.2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">waf</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">target</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> bin</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">arducopter</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">upload</span></span></code></pre></div><pre><code>This allows to set a destination to which the \`--upload\` option will upload the binary. Under the hood it installs to a temporary location and calls \`rsync &lt;temp_install_location&gt;/ &lt;destination&gt;\`.

On Linux boards there&#39;s also an install command, which will install to a certain directory, just like the temporary install above does. This can be used by distributors to create .deb, .rpm or other package types:
</code></pre><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">waf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> copter</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    DESTDIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">my</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">temporary</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">location</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">waf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> install</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\`\`\`php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-   **Use different targets**</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    The build commands in the items above use \`</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">copter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\` as argument. This builds all binaries that fall under the &quot;copter&quot; group. See the section [Advanced usage](https://github.com/ArduPilot/ardupilot/blob/master/BUILD.md#advanced-usage) below for more details regarding groups.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    This shows a list of all possible targets:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\`\`\`</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bash</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">waf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> list</span></span></code></pre></div><pre><code>For example, to build only a single binary:
</code></pre><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    # Quad frame of ArduCopter</span></span>
<span class="line"><span>    ./waf --targets bin/arducopter</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    # unit test of our math functions</span></span>
<span class="line"><span>    ./waf --targets tests/test_math</span></span>
<span class="line"><span>\`\`\`php</span></span>
<span class="line"><span>-   **Other options**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    It&#39;s possible to see all available commands and options:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>\`\`\`php</span></span>
<span class="line"><span>    ./waf -h</span></span></code></pre></div><pre><code>Also, take a look on the [Advanced section](https://github.com/ArduPilot/ardupilot/blob/master/BUILD.md#advanced-usage) below.
</code></pre><h3 id="advanced-usage" tabindex="-1">Advanced usage <a class="header-anchor" href="#advanced-usage" aria-label="Permalink to &quot;Advanced usage&quot;">​</a></h3><p>This section contains some explanations on how the Waf build system works and how you can use more advanced features.</p><p>Waf build system is composed of commands. For example, the command below (<code>configure</code>) is for configuring the build with all the options used by this particular build.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Configure the Linux board</span></span>
<span class="line"><span>./waf configure --board=linux</span></span></code></pre></div><p>Consequently, in order to build, a &quot;build&quot; command is issued, thus <code>waf build</code>. That is the default command, so calling just <code>waf</code> is enough:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Build programs from bin group</span></span>
<span class="line"><span>./waf</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Waf also accepts &#39;-j&#39; option to parallelize the build.</span></span>
<span class="line"><span>./waf -j8</span></span></code></pre></div><p>By default waf tries to parallelize the build automatically to all processors so the <code>-j</code> option is usually not needed, unless you are using icecc (thus you want a bigger value) or you don&#39;t want to stress your machine with the build.</p><h3 id="program-groups" tabindex="-1">Program groups <a class="header-anchor" href="#program-groups" aria-label="Permalink to &quot;Program groups&quot;">​</a></h3><p>Program groups are used to represent a class of programs. They can be used to build all programs of a certain class without having to specify each program. It&#39;s possible for two groups to overlap, except when both groups are main groups. In other words, a program can belong to more than one group, but only to one main group.</p><p>There&#39;s a special group, called &quot;all&quot;, that comprises all programs.</p><p><strong>Main groups</strong></p><p>The main groups form a partition of all programs. Besides separating the programs logically, they also define where they are built.</p><p>The main groups are:</p><ul><li>bin: <em>the main binaries, that is, ardupilot&#39;s main products - the vehicles and Antenna Tracker</em></li><li>tools</li><li>examples: <em>programs that show how certain libraries are used or to simply test their operation</em></li><li>benchmarks: <em>requires <code>--enable-benchmarks</code> during configurarion</em></li><li>tests: <em>basically unit tests to ensure changes don&#39;t break the system&#39;s logic</em></li></ul><p>All build files are placed under <code>build/&lt;board&gt;/</code>, where <code>&lt;board&gt;</code> represents the board/platform you selected during configuration. Each main program group has a folder with its name directly under <code>build/&lt;board&gt;/</code>. Thus, a program will be stored in <code>build/&lt;board&gt;/&lt;main_group&gt;/</code>, where <code>&lt;main_group&gt;</code> is the main group the program belongs to. For example, for a linux build, arduplane, which belongs to the main group &quot;bin&quot;, will be located at <code>build/linux/bin/arduplane</code>.</p><p><strong>Main product groups</strong></p><p>Those are groups for ardupilot&#39;s main products. They contain programs for the product they represent. Currently only the &quot;copter&quot; group has more than one program - one for each frame type.</p><p>The main product groups are:</p><ul><li>antennatracker</li><li>copter</li><li>plane</li><li>rover</li></ul><p><strong>Building a program group</strong></p><p>Ardupilot adds to waf an option called <code>--program-group</code>, which receives as argument the group you want it to build. For a build command, if you don&#39;t pass any of <code>--targets</code> or <code>--program-group</code>, then the group &quot;bin&quot; is selected by default. The option <code>--program-group</code> can be passed multiple times.</p><p>Examples:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Group bin is the default one</span></span>
<span class="line"><span>./waf</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Build all vehicles and Antenna Tracker</span></span>
<span class="line"><span>./waf --program-group bin</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Build all benchmarks and tests</span></span>
<span class="line"><span>./waf --program-group benchmarks --program-group tests</span></span></code></pre></div><p><strong>Shortcut for program groups</strong></p><p>For less typing, you can use the group name as the command to waf. Examples:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Build all vehicles and Antenna Tracker</span></span>
<span class="line"><span>./waf bin</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Build all examples</span></span>
<span class="line"><span>./waf examples</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Build arducopter binaries</span></span>
<span class="line"><span>./waf copter</span></span></code></pre></div><h3 id="building-a-specific-program" tabindex="-1">Building a specific program <a class="header-anchor" href="#building-a-specific-program" aria-label="Permalink to &quot;Building a specific program&quot;">​</a></h3><p>In order to build a specific program, you just need to pass its path relative to <code>build/&lt;board&gt;/</code> to the option <code>--targets</code>. Example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Build arducopter for quad frame</span></span>
<span class="line"><span>./waf --targets bin/arducopter</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Build vectors unit test</span></span>
<span class="line"><span>./waf --targets tests/test_vectors</span></span></code></pre></div><h3 id="checking" tabindex="-1">Checking <a class="header-anchor" href="#checking" aria-label="Permalink to &quot;Checking&quot;">​</a></h3><p>The command <code>check</code> builds all programs and then executes the relevant tests. In that context, a relevant test is a program from the group &quot;tests&quot; that makes one of the following statements true:</p><ul><li>it&#39;s the first time the test is built since the last cleanup or when the project was cloned.</li><li>the program had to be rebuilt (due to modifications in the code or dependencies, for example)</li><li>the test program failed in the previous check.</li></ul><p>That is, the tests are run only if necessary. If you want waf to run all tests, then you can use either option <code>--alltests</code> or the shortcut command <code>check-all</code>.</p><p>Examples:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Build everything and run relevant tests</span></span>
<span class="line"><span>./waf check</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Build everything and run all tests</span></span>
<span class="line"><span>./waf check --alltests</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Build everything and run all tests</span></span>
<span class="line"><span>./waf check-all</span></span></code></pre></div><h3 id="debugging" tabindex="-1">Debugging <a class="header-anchor" href="#debugging" aria-label="Permalink to &quot;Debugging&quot;">​</a></h3><p>It&#39;s possible to pass the option <code>--debug</code> to the <code>configure</code> command. That will set compiler flags to store debugging information in the binaries so that you can use them with <code>gdb</code>, for example. That option might come handy when using SITL.</p><h4 id="build-system-wrappers" tabindex="-1">Build-system wrappers <a class="header-anchor" href="#build-system-wrappers" aria-label="Permalink to &quot;Build-system wrappers&quot;">​</a></h4><p>The <code>waf</code> binary on root tree is actually a wrapper to the real <code>waf</code> that&#39;s maintained in its own submodule. It&#39;s possible to call the latter directly via <code>./modules/waf/waf-light</code> or to use an alias if you prefer typing <code>waf</code> over <code>./waf</code>.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">alias</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> waf</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;ardupilot-directory&gt;/modules/waf/waf-light&quot;</span></span></code></pre></div><p>There&#39;s also a make wrapper called <code>Makefile.waf</code>. You can use <code>make -f Makefile.waf help</code> for instructions on how to use it.</p><h4 id="command-line-help" tabindex="-1">Command line help <a class="header-anchor" href="#command-line-help" aria-label="Permalink to &quot;Command line help&quot;">​</a></h4><p>You can use <code>waf --help</code> to see information about commands and options built-in to waf as well as some quick help on those added by ardupilot.</p>`,63)])])}const g=a(t,[["render",p]]);export{u as __pageData,g as default};
